+    // Common operators and symbols not in unicodeit
+    let symbols = [
+        (r"\cdot", "·"),
+        (r"\times", "×"),
+        (r"\div", "÷"),
+        (r"\pm", "±"),
+        (r"\mp", "∓"),
+        (r"\neq", "≠"),
+        (r"\approx", "≈"),
+        (r"\equiv", "≡"),
+        (r"\leq", "≤"),
+        (r"\geq", "≥"),
+        (r"\ll", "≪"),
+        (r"\gg", "≫"),
+        (r"\subset", "⊂"),
+        (r"\supset", "⊃"),
+        (r"\subseteq", "⊆"),
+        (r"\supseteq", "⊇"),
+        (r"\cup", "∪"),
+        (r"\cap", "∩"),
+        (r"\emptyset", "∅"),
+        (r"\forall", "∀"),
+        (r"\exists", "∃"),
+        (r"\nexists", "∄"),
+        (r"\neg", "¬"),
+        (r"\land", "∧"),
+        (r"\lor", "∨"),
+        (r"\oplus", "⊕"),
+        (r"\otimes", "⊗"),
+        (r"\perp", "⊥"),
+        (r"\parallel", "∥"),
+        (r"\angle", "∠"),
+        (r"\triangle", "△"),
+        (r"\square", "□"),
+        (r"\diamond", "◇"),
+        (r"\star", "⋆"),
+        (r"\circ", "∘"),
+        (r"\bullet", "•"),
+        (r"\nabla", "∇"),
+        (r"\partial", "∂"),
+        (r"\hbar", "ℏ"),
+        (r"\ell", "ℓ"),
+        (r"\Re", "ℜ"),
